from typing import List

def game_of_life(grid: List[List[bool]], generations: int) -> List[List[bool]]:
    rows = len(grid)
    cols = len(grid[0])

    for _ in range(generations):
        new_grid = [[False] * cols for _ in range(rows)]

        for i in range(rows):
            for j in range(cols):
                live_neighbors = count_live_neighbors(grid, i, j)

