    return grid


def count_live_neighbors(grid: List[List[bool]], row: int, col: int) -> int:
    count = 0
    rows = len(grid)
    cols = len(grid[0])

    for i in range(row - 1, row + 2):
        for j in range(col - 1, col + 2):
            if i >= 0 and i < rows and j >= 0 and j < cols and (i != row or j != col):
                if grid[i][j]:
                    count += 1

    return count
